#include <stdio.h>
int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        if (X < 4) {
            printf("MILD\n");
        } else if (X < 7) {
            printf("MEDIUM\n");
        } else {
            printf("HOT\n");
        }
    }
    return 0;
}

